    '{case STATE/}',
    '    {when COMPLETED/}',
    '        Completed &END_TIME.',
    '    {otherwise/}',
    '        Started &START_TIME.',
    '{endcase/}',
    '{if DUE_ON/}',
    '    <span role="separator" aria-label="&middot;"> &middot; </span>',
    '    Due &DUE_ON.',
    '{endif/}',
    '{case RETRY_COUNT/}',
    '    {when 0/}',
    '    {when 1/}',
    '        <span role="separator" aria-label="&middot;"> &middot; </span>',
    '        &RETRY_COUNT. retry',
    '    {otherwise/}',
    '        <span role="separator" aria-label="&middot;"> &middot; </span>',
